class JWKSClient {
  constructor(jwksUri, cacheTtlMs) {
    this.jwksUri = jwksUri;
    this.cacheTtlMs = cacheTtlMs;
    this.cache = null;
    this.cacheTimestamp = 0;
    this.fetchPromise = null;
  }

  async getSigningKeys() {
    const now = Date.now();
    if (this.cache && (now - this.cacheTimestamp) < this.cacheTtlMs) {
      return this.cache;
    }

    if (this.fetchPromise) {
      return this.fetchPromise;
    }

    this.fetchPromise = this._fetchKeys();
    try {
      const keys = await this.fetchPromise;
      this.cache = keys;
      this.cacheTimestamp = Date.now();
      return keys;
    } finally {
      this.fetchPromise = null;
    }
  }

  _fetchKeys() {
    return new Promise((resolve, reject) => {
      const parsedUrl = new URL(this.jwksUri);

      if (parsedUrl.protocol !== 'https:') {
        return reject(new Error('JWKS URI must use HTTPS'));
      }

      const options = {
        hostname: parsedUrl.hostname,
        port: parsedUrl.port || 443,
        path: parsedUrl.pathname + parsedUrl.search,
        method: 'GET',
        headers: {
          'Accept': 'application/json',
          'User-Agent': 'oauth2-resource-server/1.0',
        },
        timeout: 10000,
        rejectUnauthorized: true,
      };

      const req = https.request(options, (res) => {
        if (res.statusCode !== 200) {
          return reject(new Error(`JWKS endpoint returned status ${res.statusCode}`));
        }

        let data = '';
        const maxSize = 512 * 1024;

        res.on('data', (chunk) => {
          data += chunk;
          if (data.length > maxSize) {
            req.destroy();
            reject(new Error('JWKS response too large'));
          }
        });

        res.on('end', () => {
          try {
            const jwks = JSON.parse(data);
            if (!jwks.keys || !Array.isArray(jwks.keys)) {
              return reject(new Error('Invalid JWKS format'));
            }
            const signingKeys = {};
            for (const key of jwks.keys) {
              if (key.use === 'sig' && key.kid && key.kty) {
                signingKeys[key.kid] = this._jwkToPem(key);
              }
            }
            if (Object.keys(signingKeys).length === 0) {
              return reject(new Error('No signing keys found in JWKS'));
            }
            resolve(signingKeys);
          } catch (err) {
            reject(new Error('Failed to parse JWKS response'));
          }
        });
      });

      req.on('error', (err) => {
        reject(new Error(`Failed to fetch JWKS: ${err.message}`));
      });

      req.on('timeout', () => {
        req.destroy();
        reject(new Error('JWKS request timed out'));
      });

      req.end();
    });
  }

  _jwkToPem(jwk) {
    const keyObject = crypto.createPublicKey({ key: jwk, format: 'jwk' });
    return keyObject.export({ type: 'spki', format: 'pem' });
  }

  invalidateCache() {
    this.cache = null;
    this.cacheTimestamp = 0;
  }
}

