function extractBearerToken(req) {
  const authHeader = req.headers.authorization;
  if (!authHeader) {
    return null;
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2) {
    return null;
  }

  const scheme = parts[0];
  if (scheme.toLowerCase() !== 'bearer') {
    return null;
  }

  const token = parts[1];

  if (!token || token.length === 0 || token.length > 4096) {
    return null;
  }

  const tokenRegex = /^[A-Za-z0-9\-_\.]+$/;
  if (!tokenRegex.test(token)) {
    return null;
  }

  return token;
}

function decodeTokenHeader(token) {
  try {
    const headerPart = token.split('.')[0];
    if (!headerPart) {
      return null;
    }
    const decoded = Buffer.from(headerPart, 'base64url').toString('utf8');
    const header = JSON.parse(decoded);

    if (!config.allowedAlgorithms.includes(header.alg)) {
      return null;
    }

    if (header.alg && header.alg.toLowerCase() === 'none') {
      return null;
    }

    return header;
  } catch {
    return null;
  }
}

async function validateToken(token) {
  const header = decodeTokenHeader(token);
  if (!header) {
    return { valid: false, error: 'invalid_token', description: 'Unable to decode token header or disallowed algorithm' };
  }

  if (!header.kid) {
    return { valid: false, error: 'invalid_token', description: 'Token missing key ID (kid)' };
  }

  let signingKeys;
  try {
    signingKeys = await jwksClient.getSigningKeys();
  } catch (err) {
    console.error('Failed to retrieve signing keys:', err.message);
    return { valid: false, error: 'server_error', description: 'Unable to validate token at this time' };
  }

  let publicKey = signingKeys[header.kid];

  if (!publicKey) {
    jwksClient.invalidateCache();
    try {
      signingKeys = await jwksClient.getSigningKeys();
      publicKey = signingKeys[header.kid];
    } catch (err) {
      console.error('Failed to refresh signing keys:', err.message);
      return { valid: false, error: 'server_error', description: 'Unable to validate token at this time' };
    }
  }

  if (!publicKey) {
    return { valid: false, error: 'invalid_token', description: 'Unknown signing key' };
  }

  return new Promise((resolve) => {
    const verifyOptions = {
      algorithms: config.allowedAlgorithms,
      issuer: config.issuer,
      audience: config.audience,
      clockTolerance: config.clockToleranceSec,
      complete: true,
    };

    jwt.verify(token, publicKey, verifyOptions, (err, decoded) => {
      if (err) {
        if (err.name === 'TokenExpiredError') {
          return resolve({ valid: false, error: 'invalid_token', description: 'Token has expired' });
        }
        if (err.name === 'NotBeforeError') {
          return resolve({ valid: false, error: 'invalid_token', description: 'Token is not yet valid' });
        }
        if (err.name === 'JsonWebTokenError') {
          return resolve({ valid: false, error: 'invalid_token', description: 'Token signature verification failed' });
        }
        return resolve({ valid: false, error: 'invalid_token', description: 'Token validation failed' });
      }

      const payload = decoded.payload;

      if (!payload.sub) {
        return resolve({ valid: false, error: 'invalid_token', description: 'Token missing subject claim' });
      }

      if (!payload.iat) {
        return resolve({ valid: false, error: 'invalid_token', description: 'Token missing issued-at claim' });
      }

      resolve({
        valid: true,
        payload: {
          sub: payload.sub,
          iss: payload.iss,
          aud: payload.aud,
          exp: payload.exp,
          iat: payload.iat,
          nbf: payload.nbf,
          scope: payload.scope || '',
          client_id: payload.client_id || payload.azp,
          jti: payload.jti,
        },
      });
    });
  });
}

function requireScope(...requiredScopes) {
  return (req, res, next) => {
    if (!req.tokenPayload) {
      return sendAuthError(res, 401, 'invalid_token', 'No token payload available');
    }

    const tokenScopes = (req.tokenPayload.scope || '').split(' ').filter(Boolean);
    const hasRequiredScope = requiredScopes.some((scope) => tokenScopes.includes(scope));

    if (!hasRequiredScope) {
      return sendAuthError(res, 403, 'insufficient_scope', `Required scope: ${requiredScopes.join(' or ')}`, requiredScopes.join(' '));
    }

    next();
  };
}

function sendAuthError(res, statusCode, error, description, scope) {
  let wwwAuthenticate = `Bearer realm="${config.audience}"`;
  if (error) {
    wwwAuthenticate += `, error="${error}"`;
  }
  if (description) {
    wwwAuthenticate += `, error_description="${description}"`;
  }
  if (scope) {
    wwwAuthenticate += `, scope="${scope}"`;
  }

  res.set('WWW-Authenticate', wwwAuthenticate);
  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.status(statusCode).json({
    error,
    error_description: description,
  });
}

async function authenticateToken(req, res, next) {
  const token = extractBearerToken(req);

  if (!token) {
    return sendAuthError(res, 401, 'invalid_request', 'Missing or malformed Bearer token');
  }

  try {
    const result = await validateToken(token);

    if (!result.valid) {
      const statusCode = result.error === 'server_error' ? 503 : 401;
      return sendAuthError(res, statusCode, result.error, result.description);
    }

    req.tokenPayload = result.payload;

    req.headers['x-authenticated-subject'] = result.payload.sub;
    req.headers['x-authenticated-client'] = result.payload.client_id || '';
    req.headers['x-authenticated-scope'] = result.payload.scope || '';

    next();
  } catch (err) {
    console.error('Unexpected error during token validation:', err.message);
    return sendAuthError(res, 503, 'server_error', 'Unable to validate token at this time');
  }
}

